import sqlite3
from pathlib import Path


ROOT = Path(__file__).resolve().parents[1]


def read_sql(name):
    return (ROOT / "sql" / name).read_text(encoding="ascii")


def make_db():
    db = sqlite3.connect(":memory:")
    db.executescript(
        """
        CREATE TABLE export_profile (
            profile_name TEXT PRIMARY KEY,
            field_separator TEXT NOT NULL CHECK (length(field_separator) = 1),
            record_separator TEXT NOT NULL CHECK (record_separator IN ('LF', 'CRLF'))
        );

        CREATE TABLE customer (
            customer_id INTEGER PRIMARY KEY,
            display_name TEXT
        );

        CREATE TABLE fulfillment_order (
            order_id INTEGER PRIMARY KEY,
            delivery_note TEXT
        );
        """
    )
    db.execute("INSERT INTO export_profile VALUES ('semicolon', ';', 'LF')")
    db.execute("INSERT INTO customer VALUES (7, 'North;Annex')")
    db.executemany(
        "INSERT INTO fulfillment_order VALUES (?, ?)",
        [
            (41, "Gate; after five"),
            (42, 'Say "ready"'),
        ],
    )
    return db


def test_customer_values_containing_the_selected_separator_are_quoted():
    db = make_db()
    rendered = db.execute(
        read_sql("render_customer_row.sql"),
        {"profile_name": "semicolon", "customer_id": 7},
    ).fetchone()[0]

    assert rendered == '7;"North;Annex"\n'


def test_order_quoting_uses_the_selected_separator_and_doubles_quotes():
    db = make_db()
    first = db.execute(
        read_sql("render_order_row.sql"),
        {"profile_name": "semicolon", "order_id": 41},
    ).fetchone()[0]
    second = db.execute(
        read_sql("render_order_row.sql"),
        {"profile_name": "semicolon", "order_id": 42},
    ).fetchone()[0]

    assert first == '41;"Gate; after five"\n'
    assert second == '42;"Say ""ready"""\n'
